head.b:skin:
html,
body {
  margin: 0;
  min-height: 100%;
}

.navbar,
.blogger-clickTrap,
.blogger-system,
.widget-content {
  display: none !important;
}

#oxygenWeatherBloggerRoot {
  min-height: 100vh;
}

:root {
    --ink: #17212f;
    --muted: #667085;
    --subtle: #8a96a8;
    --surface: #ffffff;
    --surface-soft: #f7fafc;
    --line: #d8e0e8;
    --teal: #0f766e;
    --teal-dark: #124b50;
    --amber: #d97706;
    --coral: #dc4a36;
    --green: #178a55;
    --blue: #2563eb;
    --shadow: 0 18px 42px rgba(23, 33, 47, 0.12);
    --radius: 8px;
    --weather-accent: #0f766e;
    --weather-accent-2: #2563eb;
    --weather-glow: rgba(15, 118, 110, 0.24);
    --weather-panel: rgba(240, 253, 250, 0.92);
}

* {
    box-sizing: border-box;
}

html {
    min-height: 100%;
    max-width: 100%;
    overflow-x: clip;
}

body {
    min-height: 100vh;
    margin: 0;
    font-family: "Inter", system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
    color: var(--ink);
    background:
        radial-gradient(circle at 15% 18%, var(--weather-glow), transparent 28%),
        radial-gradient(circle at 86% 70%, rgba(220, 74, 54, 0.16), transparent 24%),
        linear-gradient(135deg, rgba(15, 118, 110, 0.16), rgba(255, 255, 255, 0.84) 44%, rgba(37, 99, 235, 0.12)),
        #f5f8fb;
    overflow-x: clip;
}

body.has-earthquake-overlay {
    overflow: hidden;
}

body.has-login-panel {
    overflow: hidden;
}

body[data-weather="storm"] .storm-flash {
    animation-duration: 5.4s;
}

body[data-weather="storm"] .rain-field {
    opacity: 0.32;
}

body[data-weather="rain"] .rain-field,
body[data-weather="snow"] .rain-field {
    opacity: 0.34;
}

body[data-weather="clear"] .ribbon-one {
    opacity: 0.9;
}

body[data-weather="mist"] .weather-effects::before {
    opacity: 0.45;
}

button,
input,
textarea {
    font: inherit;
}

button {
    border: 0;
}

i[data-lucide] {
    width: 18px;
    height: 18px;
    display: inline-grid;
    place-items: center;
    flex: 0 0 auto;
    color: currentColor;
}

i[data-lucide]::before {
    content: "";
    width: 12px;
    height: 12px;
    border: 2px solid currentColor;
    border-radius: 4px;
    opacity: 0.82;
    transform: rotate(45deg);
}

.menu-button i[data-lucide],
.live-brief-pills i[data-lucide],
.mail-alerts-meta i[data-lucide] {
    display: none;
}

button:disabled {
    cursor: not-allowed;
    opacity: 0.62;
    box-shadow: none;
}

button:focus-visible,
input:focus-visible,
textarea:focus-visible,
a:focus-visible {
    outline: 3px solid rgba(37, 99, 235, 0.28);
    outline-offset: 2px;
}

a {
    color: inherit;
    text-decoration: none;
}

.app-shell {
    position: relative;
    z-index: 1;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.weather-effects {
    position: fixed;
    inset: 0;
    z-index: 0;
    overflow: hidden;
    pointer-events: none;
}

.weather-effects::before {
    content: "";
    position: absolute;
    inset: -20% -10%;
    background:
        linear-gradient(110deg, transparent 0 24%, rgba(255, 255, 255, 0.34) 36%, transparent 48%),
        linear-gradient(145deg, rgba(37, 99, 235, 0.12), transparent 42%, rgba(220, 74, 54, 0.1));
    opacity: 0.72;
    transform: translateX(-18%);
    animation: skySweep 14s ease-in-out infinite;
}

.sky-ribbon {
    position: absolute;
    left: 50%;
    width: 120vw;
    height: 28vh;
    filter: blur(28px);
    opacity: 0.72;
    transform-origin: center;
    animation: ribbonDrift 18s ease-in-out infinite alternate;
}

.ribbon-one {
    top: 5%;
    background: linear-gradient(90deg, rgba(15, 118, 110, 0), rgba(15, 118, 110, 0.36), rgba(217, 119, 6, 0.24), rgba(15, 118, 110, 0));
    transform: translateX(-50%) rotate(-8deg);
}

.ribbon-two {
    bottom: 4%;
    background: linear-gradient(90deg, rgba(37, 99, 235, 0), rgba(37, 99, 235, 0.2), rgba(220, 74, 54, 0.18), rgba(15, 118, 110, 0));
    transform: translateX(-50%) rotate(9deg);
    animation-delay: -7s;
}

.storm-flash {
    position: absolute;
    inset: 0;
    background: linear-gradient(120deg, transparent 0 50%, rgba(255, 255, 255, 0.72) 52%, transparent 56%);
    opacity: 0;
    animation: stormFlash 9s steps(1, end) infinite;
}

.rain-field {
    position: absolute;
    inset: -18%;
    background-image: repeating-linear-gradient(
        115deg,
        rgba(15, 118, 110, 0.14) 0 2px,
        transparent 2px 20px
    );
    background-size: 170px 170px;
    opacity: 0.2;
    transform: rotate(2deg);
    animation: rainMove 9s linear infinite;
}

.rain-field-two {
    opacity: 0.14;
    background-size: 230px 230px;
    animation-duration: 14s;
    animation-direction: reverse;
}

.wind-streams span {
    position: absolute;
    left: -20vw;
    width: 34vw;
    height: 2px;
    border-radius: 999px;
    background: linear-gradient(90deg, transparent, rgba(18, 75, 80, 0.24), transparent);
    animation: windRush 8s ease-in-out infinite;
}

.wind-streams span:nth-child(1) {
    top: 18%;
}

.wind-streams span:nth-child(2) {
    top: 42%;
    animation-delay: -2.5s;
}

.wind-streams span:nth-child(3) {
    top: 66%;
    animation-delay: -5s;
}

.wind-streams span:nth-child(4) {
    top: 84%;
    animation-delay: -7s;
}

.float-icon {
    position: absolute;
    display: grid;
    place-items: center;
    width: 76px;
    height: 76px;
    color: rgba(15, 118, 110, 0.22);
    animation: iconFloat 12s ease-in-out infinite;
}

.float-icon svg {
    width: 76px;
    height: 76px;
    stroke-width: 1.2;
}

.float-cloud {
    top: 15%;
    right: 8%;
}

.float-rain {
    top: 54%;
    left: 7%;
    color: rgba(37, 99, 235, 0.18);
    animation-delay: -4s;
}

.float-bolt {
    right: 13%;
    bottom: 11%;
    color: rgba(217, 119, 6, 0.2);
    animation-delay: -8s;
}

.topbar {
    position: sticky;
    top: 12px;
    z-index: 100;
    width: min(1180px, calc(100% - 32px));
    margin: 18px auto 0;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 16px;
    padding: 12px;
    background: rgba(255, 255, 255, 0.68);
    border: 1px solid rgba(216, 224, 232, 0.72);
    border-radius: var(--radius);
    box-shadow: 0 8px 26px rgba(23, 33, 47, 0.08);
    backdrop-filter: blur(20px);
    animation: riseIn 520ms ease both;
}

.brand-button {
    display: inline-flex;
    align-items: center;
    gap: 12px;
    min-width: 0;
    padding: 0;
    color: var(--ink);
    background: transparent;
    cursor: pointer;
    text-align: left;
}

.brand-mark {
    width: 44px;
    height: 44px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    flex: 0 0 auto;
    color: #fff;
    background: var(--teal);
    border-radius: var(--radius);
    animation: brandPulse 3s ease-in-out infinite;
}

.brand-mark svg,
button svg,
a svg {
    width: 18px;
    height: 18px;
    stroke-width: 2.2;
}

.brand-name,
.brand-owner {
    display: block;
    line-height: 1.2;
}

.brand-name {
    font-weight: 800;
    font-size: 1rem;
}

.brand-owner {
    margin-top: 2px;
    color: var(--muted);
    font-size: 0.78rem;
    font-weight: 600;
}

.topbar-actions {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: 10px;
    min-width: 0;
}

.icon-button,
.primary-button,
.secondary-button,
.header-blog-link,
.unit-button,
.recent-chip {
    min-height: 44px;
    border-radius: var(--radius);
    cursor: pointer;
    transition: background-color 160ms ease, border-color 160ms ease, color 160ms ease, transform 160ms ease, box-shadow 160ms ease;
}

.icon-button:hover,
.primary-button:hover,
.secondary-button:hover,
.header-blog-link:hover,
.unit-button:hover,
.recent-chip:hover,
.susnata-codes-link:hover {
    transform: translateY(-2px);
}

.icon-button {
    width: 44px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: var(--ink);
    background: var(--surface-soft);
    border: 1px solid var(--line);
}

.icon-button:hover,
.secondary-button:hover,
.recent-chip:hover {
    border-color: rgba(15, 118, 110, 0.42);
    color: var(--teal);
}

.primary-button,
.secondary-button {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 0 16px;
    font-weight: 800;
    white-space: nowrap;
}

.primary-button {
    position: relative;
    overflow: hidden;
    color: #fff;
    background: var(--teal);
    box-shadow: 0 12px 24px rgba(15, 118, 110, 0.24);
}

.primary-button::before {
    content: "";
    position: absolute;
    inset: 0;
    background: linear-gradient(110deg, transparent 0 34%, rgba(255, 255, 255, 0.34) 46%, transparent 58%);
    transform: translateX(-120%);
    animation: buttonShine 3.8s ease-in-out infinite;
}

.primary-button > * {
    position: relative;
    z-index: 1;
}

.primary-button:hover {
    background: #0b665f;
}

.secondary-button {
    color: var(--ink);
    background: var(--surface);
    border: 1px solid var(--line);
}

.header-blog-link {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 0 14px;
    color: var(--teal-dark);
    background: rgba(255, 255, 255, 0.34);
    border: 1px solid rgba(15, 118, 110, 0.24);
    font-size: 0.82rem;
    font-weight: 900;
    white-space: nowrap;
    box-shadow: 0 12px 24px rgba(23, 33, 47, 0.08);
}

.header-blog-link:hover {
    color: #fff;
    background: rgba(15, 118, 110, 0.82);
    border-color: rgba(15, 118, 110, 0.72);
}

.menu-button {
    position: relative;
    overflow: hidden;
    min-width: 126px;
    color: var(--ink);
    background: rgba(255, 255, 255, 0.22);
    border: 1px solid rgba(15, 118, 110, 0.28);
    box-shadow: 0 14px 28px rgba(23, 33, 47, 0.1);
    backdrop-filter: blur(14px);
}

.menu-button::before {
    content: "";
    position: absolute;
    inset: 0;
    background: linear-gradient(110deg, transparent 0 34%, rgba(15, 118, 110, 0.16) 48%, transparent 60%);
    transform: translateX(-120%);
    animation: buttonShine 4.2s ease-in-out infinite;
}

.menu-button > * {
    position: relative;
    z-index: 1;
}

.menu-button:hover,
.menu-button.is-open {
    color: var(--teal-dark);
    background: rgba(255, 255, 255, 0.48);
    border-color: rgba(15, 118, 110, 0.7);
    box-shadow: 0 18px 34px rgba(15, 118, 110, 0.25);
}

.menu-button.is-open .menu-chevron {
    transform: rotate(180deg);
}

.menu-chevron {
    width: 16px;
    height: 16px;
    transition: transform 180ms ease;
}

.segmented-control {
    display: inline-grid;
    grid-template-columns: repeat(2, 40px);
    height: 44px;
    padding: 3px;
    background: var(--surface-soft);
    border: 1px solid var(--line);
    border-radius: var(--radius);
}

.unit-button {
    min-height: 36px;
    height: 36px;
    color: var(--muted);
    background: transparent;
    font-weight: 800;
}

.unit-button.is-active {
    color: #fff;
    background: var(--ink);
    box-shadow: 0 8px 18px rgba(23, 33, 47, 0.18);
}

.contact-menu {
    position: relative;
}

.contact-panel {
    position: absolute;
    top: calc(100% + 8px);
    right: 0;
    width: 292px;
    padding: 10px;
    background: rgba(255, 255, 255, 0.96);
    border: 1px solid rgba(216, 224, 232, 0.95);
    border-radius: var(--radius);
    box-shadow: 0 24px 54px rgba(23, 33, 47, 0.18);
    backdrop-filter: blur(18px);
    z-index: 80;
    animation: menuDrop 180ms ease both;
}

.menu-heading {
    display: block;
    padding: 10px 10px 6px;
    color: var(--teal);
    font-size: 0.72rem;
    font-weight: 900;
    letter-spacing: 0;
    text-transform: uppercase;
}

.contact-panel a,
.contact-panel button {
    width: 100%;
    min-height: 44px;
    display: flex;
    align-items: center;
    gap: 12px;
    padding: 0 12px;
    border-radius: 6px;
    color: var(--ink);
    background: transparent;
    font-weight: 700;
    text-align: left;
    cursor: pointer;
    transition: background-color 160ms ease, color 160ms ease, transform 160ms ease;
}

.contact-panel a:hover,
.contact-panel button:hover {
    color: var(--teal);
    background: #edf8f6;
    transform: translateX(3px);
}

.contact-panel a svg,
.contact-panel button svg {
    flex: 0 0 auto;
    width: 18px;
    height: 18px;
    color: var(--teal);
}

.dashboard {
    width: min(1180px, calc(100% - 32px));
    margin: 28px auto 0;
    flex: 1;
}

.search-toolbar {
    display: grid;
    grid-template-columns: minmax(220px, 0.78fr) minmax(320px, 1.42fr);
    align-items: end;
    gap: 22px;
    padding: 22px;
    background: rgba(255, 255, 255, 0.92);
    border: 1px solid rgba(216, 224, 232, 0.88);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    animation: riseIn 620ms ease 90ms both;
}

.search-toolbar > div,
.mail-alerts-copy,
.mail-alerts-form {
    min-width: 0;
}

.eyebrow {
    margin: 0 0 8px;
    color: var(--teal);
    font-size: 0.76rem;
    font-weight: 800;
    letter-spacing: 0;
    text-transform: uppercase;
}

h1,
h2,
p {
    margin-top: 0;
}

h1 {
    margin-bottom: 0;
    font-size: 3rem;
    line-height: 1;
    letter-spacing: 0;
}

.search-form {
    display: grid;
    grid-template-columns: minmax(220px, 1fr) auto auto;
    gap: 10px;
    align-items: center;
}

.input-control {
    min-height: 52px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 0 14px;
    background: var(--surface-soft);
    border: 1px solid var(--line);
    border-radius: var(--radius);
}

.input-control svg {
    flex: 0 0 auto;
    color: var(--teal);
}

.input-control input {
    width: 100%;
    min-width: 0;
    border: 0;
    outline: 0;
    color: var(--ink);
    background: transparent;
    font-weight: 700;
}

.input-control input::placeholder {
    color: var(--subtle);
    font-weight: 600;
}

.recent-searches {
    display: flex;
    align-items: center;
    flex-wrap: wrap;
    gap: 8px;
    margin: 14px 0 0;
}

.recent-chip {
    min-height: 36px;
    padding: 0 12px;
    color: var(--ink);
    background: rgba(255, 255, 255, 0.82);
    border: 1px solid var(--line);
    font-size: 0.9rem;
    font-weight: 800;
}

.status-message,
.loading-panel {
    margin-top: 16px;
    padding: 14px 16px;
    border-radius: var(--radius);
    background: var(--surface);
    border: 1px solid var(--line);
    box-shadow: 0 10px 26px rgba(23, 33, 47, 0.08);
}

.status-message {
    color: #923018;
    background: #fff5f1;
    border-color: #f8c8ba;
    font-weight: 700;
    overflow-wrap: anywhere;
}

.status-message.is-success {
    color: #0f6d42;
    background: #effaf4;
    border-color: #bde9cd;
}

.loading-panel {
    display: inline-flex;
    align-items: center;
    gap: 12px;
    color: var(--muted);
    font-weight: 800;
    animation: glowStatus 1.9s ease-in-out infinite;
}

.mail-alerts-panel {
    display: grid;
    grid-template-columns: minmax(220px, 0.75fr) minmax(360px, 1.25fr);
    align-items: center;
    gap: 18px;
    margin-top: 16px;
    padding: 20px;
    overflow: hidden;
    background:
        linear-gradient(135deg, rgba(255, 255, 255, 0.94), rgba(237, 248, 246, 0.92)),
        var(--surface);
    border: 1px solid rgba(216, 224, 232, 0.9);
    border-radius: var(--radius);
    box-shadow: 0 16px 36px rgba(23, 33, 47, 0.1);
    animation: riseIn 680ms ease 120ms both;
}

.mail-alerts-copy h2 {
    margin-bottom: 12px;
    font-size: 1.55rem;
    line-height: 1.12;
    letter-spacing: 0;
}

.mail-alerts-meta {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}

.mail-alerts-meta span {
    min-height: 34px;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    padding: 0 10px;
    color: var(--teal-dark);
    background: rgba(15, 118, 110, 0.1);
    border: 1px solid rgba(15, 118, 110, 0.18);
    border-radius: 6px;
    font-size: 0.78rem;
    font-weight: 900;
}

.mail-alerts-meta svg {
    width: 16px;
    height: 16px;
}

.mail-alerts-form {
    display: grid;
    grid-template-columns: minmax(180px, 1fr) minmax(160px, 0.9fr) auto auto auto;
    gap: 10px;
    align-items: center;
}

.mail-alerts-preferences {
    grid-column: 1 / -1;
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 10px;
}

.mail-toggle,
.mail-field {
    min-height: 54px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px 12px;
    color: var(--ink);
    background: var(--surface-soft);
    border: 1px solid var(--line);
    border-radius: var(--radius);
    font-weight: 800;
}

.mail-toggle input {
    width: 18px;
    height: 18px;
    accent-color: var(--teal);
}

.mail-field {
    align-items: stretch;
    flex-direction: column;
    gap: 5px;
}

.mail-field span {
    color: var(--muted);
    font-size: 0.72rem;
    font-weight: 900;
    text-transform: uppercase;
}

.mail-field input,
.mail-field select {
    width: 100%;
    min-width: 0;
    border: 0;
    outline: 0;
    color: var(--ink);
    background: transparent;
    font-weight: 800;
}

.mail-server-status,
.mail-alerts-status {
    grid-column: 1 / -1;
    margin: 2px 0 0;
    padding: 10px 12px;
    border-radius: 6px;
    font-size: 0.86rem;
    font-weight: 800;
}

.mail-server-status.is-success,
.mail-alerts-status.is-success {
    color: #0f6d42;
    background: #effaf4;
    border: 1px solid #bde9cd;
}

.mail-server-status.is-warning {
    color: #8a4b04;
    background: #fffbeb;
    border: 1px solid #fde68a;
}

.mail-alerts-status.is-error {
    color: #923018;
    background: #fff5f1;
    border: 1px solid #f8c8ba;
}

.mail-alerts-status.is-info {
    color: #1d4f91;
    background: #eef5ff;
    border: 1px solid #c9ddff;
}

.loader {
    width: 22px;
    height: 22px;
    border: 3px solid #dbe5ec;
    border-top-color: var(--teal);
    border-radius: 50%;
    animation: spin 900ms linear infinite;
}

@keyframes spin {
    to {
        transform: rotate(360deg);
    }
}

@keyframes skySweep {
    0%, 100% {
        transform: translateX(-18%) scale(1);
    }
    50% {
        transform: translateX(12%) scale(1.05);
    }
}

@keyframes ribbonDrift {
    0% {
        transform: translateX(-52%) rotate(-8deg) translateY(0);
    }
    100% {
        transform: translateX(-48%) rotate(7deg) translateY(22px);
    }
}

@keyframes stormFlash {
    0%, 66%, 70%, 100% {
        opacity: 0;
    }
    67% {
        opacity: 0.34;
    }
    68% {
        opacity: 0.08;
    }
    69% {
        opacity: 0.26;
    }
}

@keyframes rainMove {
    to {
        background-position: -340px 520px;
    }
}

@keyframes windRush {
    0% {
        transform: translateX(0) scaleX(0.8);
        opacity: 0;
    }
    18%, 70% {
        opacity: 1;
    }
    100% {
        transform: translateX(140vw) scaleX(1.25);
        opacity: 0;
    }
}

@keyframes iconFloat {
    0%, 100% {
        transform: translateY(0) rotate(-4deg);
    }
    50% {
        transform: translateY(-24px) rotate(5deg);
    }
}

@keyframes riseIn {
    from {
        opacity: 0;
        transform: translateY(20px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

@keyframes currentPanelIn {
    from {
        opacity: 0;
        transform: translateY(26px) scale(0.98);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
}

@keyframes cardPop {
    from {
        opacity: 0;
        transform: translateY(16px) scale(0.96);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
}

@keyframes weatherIconFloat {
    0%, 100% {
        transform: translateY(0) scale(1);
    }
    50% {
        transform: translateY(-10px) scale(1.05);
    }
}

@keyframes panelWave {
    0%, 100% {
        transform: rotate(-12deg) translate3d(0, 0, 0);
        opacity: 0.4;
    }
    50% {
        transform: rotate(-6deg) translate3d(22px, -14px, 0);
        opacity: 0.72;
    }
}

@keyframes orbitSpin {
    to {
        transform: rotate(360deg);
    }
}

@keyframes brandPulse {
    0%, 100% {
        box-shadow: 0 0 0 0 rgba(15, 118, 110, 0.28);
    }
    50% {
        box-shadow: 0 0 0 8px rgba(15, 118, 110, 0);
    }
}

@keyframes buttonShine {
    0%, 46% {
        transform: translateX(-120%);
    }
    72%, 100% {
        transform: translateX(120%);
    }
}

@keyframes glowStatus {
    0%, 100% {
        box-shadow: 0 10px 26px rgba(23, 33, 47, 0.08);
    }
    50% {
        box-shadow: 0 16px 34px rgba(15, 118, 110, 0.18);
    }
}

@keyframes menuDrop {
    from {
        opacity: 0;
        transform: translateY(-8px) scale(0.98);
    }
    to {
        opacity: 1;
        transform: translateY(0) scale(1);
    }
}

.weather-dashboard {
    display: grid;
    grid-template-columns: minmax(300px, 0.9fr) minmax(420px, 1.1fr);
    gap: 18px;
    margin-top: 18px;
    min-width: 0;
}

.current-panel {
    position: relative;
    min-width: 0;
    min-height: 322px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    gap: 24px;
    padding: 28px;
    overflow: hidden;
    color: #fff;
    background:
        linear-gradient(135deg, rgba(18, 75, 80, 0.98), rgba(15, 118, 110, 0.92) 55%, rgba(217, 119, 6, 0.82)),
        var(--teal-dark);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    animation: currentPanelIn 760ms cubic-bezier(0.19, 1, 0.22, 1) both;
}

.current-panel::before,
.current-panel::after {
    content: "";
    position: absolute;
    inset: auto auto -30% -15%;
    width: 72%;
    height: 56%;
    border: 1px solid rgba(255, 255, 255, 0.16);
    transform: rotate(-12deg);
    animation: panelWave 9s ease-in-out infinite;
}

.current-panel::after {
    inset: -24% -16% auto auto;
    width: 64%;
    height: 48%;
    animation-delay: -4s;
}

.current-panel > * {
    position: relative;
    z-index: 1;
}

.current-copy h2 {
    margin-bottom: 10px;
    font-size: 2.25rem;
    line-height: 1.08;
    letter-spacing: 0;
    overflow-wrap: anywhere;
}

.current-copy p:not(.eyebrow) {
    margin: 0;
    color: rgba(255, 255, 255, 0.82);
    font-weight: 700;
}

.current-panel .eyebrow {
    color: rgba(255, 255, 255, 0.76);
}

.temperature-block {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 18px;
}

.temperature-block img {
    width: 112px;
    height: 112px;
    flex: 0 0 auto;
    object-fit: contain;
    filter: drop-shadow(0 12px 18px rgba(0, 0, 0, 0.2));
    animation: weatherIconFloat 4.8s ease-in-out infinite;
}

.temperature-block strong,
.temperature-block span {
    display: block;
    text-align: right;
}

.temperature-block strong {
    font-size: 4rem;
    line-height: 0.95;
    letter-spacing: 0;
    text-shadow: 0 18px 34px rgba(0, 0, 0, 0.22);
}

.temperature-block span {
    margin-top: 8px;
    color: rgba(255, 255, 255, 0.78);
    font-weight: 800;
}

.metrics-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 12px;
}

.metric-card,
.forecast-card {
    min-width: 0;
    min-height: 116px;
    padding: 16px;
    background: rgba(255, 255, 255, 0.94);
    border: 1px solid rgba(216, 224, 232, 0.92);
    border-radius: var(--radius);
    box-shadow: 0 12px 28px rgba(23, 33, 47, 0.08);
    transition: transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease;
}

.metric-card:hover,
.forecast-card:hover,
.air-chip:hover {
    transform: translateY(-4px);
    border-color: rgba(15, 118, 110, 0.4);
    box-shadow: 0 18px 38px rgba(23, 33, 47, 0.13);
}

.metric-card {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    animation: cardPop 520ms ease both;
}

.metric-card:nth-child(2) { animation-delay: 60ms; }
.metric-card:nth-child(3) { animation-delay: 120ms; }
.metric-card:nth-child(4) { animation-delay: 180ms; }
.metric-card:nth-child(5) { animation-delay: 240ms; }
.metric-card:nth-child(6) { animation-delay: 300ms; }
.metric-card:nth-child(7) { animation-delay: 360ms; }
.metric-card:nth-child(8) { animation-delay: 420ms; }
.metric-card:nth-child(9) { animation-delay: 480ms; }

.metric-label {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
    color: var(--muted);
    font-size: 0.82rem;
    font-weight: 800;
}

.metric-label svg {
    width: 18px;
    height: 18px;
    color: var(--teal);
}

.metric-value {
    margin-top: 20px;
    color: var(--ink);
    font-size: 1.48rem;
    font-weight: 800;
    line-height: 1.1;
}

.metric-note {
    margin-top: 4px;
    color: var(--subtle);
    font-size: 0.78rem;
    font-weight: 700;
}

.forecast-section,
.air-section {
    min-width: 0;
    grid-column: 1 / -1;
    padding: 22px;
    background: rgba(255, 255, 255, 0.92);
    border: 1px solid rgba(216, 224, 232, 0.88);
    border-radius: var(--radius);
    box-shadow: var(--shadow);
    animation: riseIn 720ms ease 160ms both;
}

.section-heading,
.air-section {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 18px;
}

.section-heading {
    margin-bottom: 16px;
}

.section-heading h2,
.air-section h2 {
    margin-bottom: 0;
    font-size: 1.45rem;
    letter-spacing: 0;
}

#forecastSource {
    color: var(--muted);
    font-size: 0.84rem;
    font-weight: 800;
}

.forecast-grid {
    display: grid;
    grid-template-columns: repeat(5, minmax(0, 1fr));
    gap: 12px;
}

.forecast-card {
    min-height: 178px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    animation: cardPop 560ms ease both;
}

.forecast-card:nth-child(2) { animation-delay: 70ms; }
.forecast-card:nth-child(3) { animation-delay: 140ms; }
.forecast-card:nth-child(4) { animation-delay: 210ms; }
.forecast-card:nth-child(5) { animation-delay: 280ms; }

.forecast-day {
    color: var(--muted);
    font-size: 0.82rem;
    font-weight: 800;
}

.forecast-card img {
    width: 54px;
    height: 54px;
    object-fit: contain;
    margin: 8px 0;
}

.forecast-temps {
    display: flex;
    align-items: baseline;
    gap: 7px;
}

.forecast-high {
    font-weight: 800;
    font-size: 1.28rem;
}

.forecast-low {
    color: var(--subtle);
    font-weight: 800;
}

.forecast-description,
.forecast-pop {
    margin: 0;
    color: var(--muted);
    font-size: 0.78rem;
    font-weight: 700;
}

.air-section {
    align-items: stretch;
}

.air-section > div:first-child {
    min-width: 180px;
}

.air-section p:last-child {
    margin: 8px 0 0;
    color: var(--muted);
    font-weight: 800;
}

.air-components {
    display: grid;
    grid-template-columns: repeat(5, minmax(72px, 1fr));
    gap: 10px;
    flex: 1;
}

.air-chip {
    min-height: 74px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    padding: 10px;
    background: var(--surface-soft);
    border: 1px solid var(--line);
    border-radius: var(--radius);
    transition: transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease;
}

.air-chip span:first-child {
    color: var(--muted);
    font-size: 0.72rem;
    font-weight: 800;
}

.air-chip span:last-child {
    margin-top: 6px;
    font-weight: 800;
}

.search-toolbar {
    position: relative;
    overflow: hidden;
    align-items: center;
    background:
        linear-gradient(135deg, rgba(255, 255, 255, 0.88), var(--weather-panel)),
        var(--surface);
    border-color: rgba(255, 255, 255, 0.86);
    box-shadow: 0 24px 62px rgba(23, 33, 47, 0.13);
}

.search-toolbar::before {
    content: "";
    position: absolute;
    inset: -60% 54% auto -10%;
    height: 180%;
    background: radial-gradient(circle, var(--weather-glow), transparent 62%);
    animation: skySweep 12s ease-in-out infinite;
}

.search-toolbar > * {
    position: relative;
    z-index: 1;
}

.search-title-block h1 {
    max-width: 560px;
    font-size: clamp(2.35rem, 5vw, 4.85rem);
    line-height: 0.9;
}

.live-brief-pills {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 16px;
}

.live-brief-pills > span,
.current-live-row span {
    min-height: 34px;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    padding: 0 10px;
    color: var(--teal-dark);
    background: rgba(255, 255, 255, 0.62);
    border: 1px solid rgba(15, 118, 110, 0.18);
    border-radius: 6px;
    font-size: 0.78rem;
    font-weight: 900;
    box-shadow: 0 8px 18px rgba(23, 33, 47, 0.06);
}

.live-brief-pills > span svg {
    width: 15px;
    height: 15px;
}

.search-form {
    padding: 8px;
    background: rgba(255, 255, 255, 0.52);
    border: 1px solid rgba(216, 224, 232, 0.72);
    border-radius: var(--radius);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.72);
}

.weather-dashboard {
    grid-template-columns: minmax(330px, 0.95fr) minmax(460px, 1.05fr);
    align-items: stretch;
}

.current-panel {
    min-height: 430px;
    background:
        radial-gradient(circle at 78% 18%, rgba(255, 255, 255, 0.24), transparent 26%),
        linear-gradient(135deg, rgba(18, 75, 80, 0.98), var(--weather-accent) 56%, var(--weather-accent-2)),
        var(--teal-dark);
    box-shadow: 0 28px 70px var(--weather-glow);
}

.current-panel::before {
    width: 86%;
    height: 68%;
    border-color: rgba(255, 255, 255, 0.2);
}

.current-panel::after {
    background: linear-gradient(135deg, rgba(255, 255, 255, 0.14), transparent);
    border-color: rgba(255, 255, 255, 0.14);
}

.current-copy h2 {
    font-size: clamp(2rem, 4vw, 3.55rem);
}

.current-live-row {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 18px;
}

.current-live-row span {
    color: #fff;
    background: rgba(255, 255, 255, 0.14);
    border-color: rgba(255, 255, 255, 0.2);
    box-shadow: none;
}

.weather-orbit {
    position: absolute;
    right: 22px;
    bottom: 18px;
    width: 148px;
    height: 148px;
    border: 1px solid rgba(255, 255, 255, 0.16);
    border-radius: 50%;
    animation: orbitSpin 18s linear infinite;
}

.weather-orbit span {
    position: absolute;
    width: 12px;
    height: 12px;
    background: rgba(255, 255, 255, 0.78);
    border-radius: 50%;
    box-shadow: 0 0 26px rgba(255, 255, 255, 0.55);
}

.weather-orbit span:nth-child(1) { top: -6px; left: 50%; }
.weather-orbit span:nth-child(2) { right: 10px; bottom: 24px; opacity: 0.62; }
.weather-orbit span:nth-child(3) { left: 16px; bottom: 34px; opacity: 0.42; }

.insights-strip {
    min-width: 0;
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 12px;
}

.insight-card {
    min-height: 142px;
    display: flex;
    gap: 14px;
    padding: 16px;
    background: rgba(255, 255, 255, 0.94);
    border: 1px solid rgba(216, 224, 232, 0.9);
    border-radius: var(--radius);
    box-shadow: 0 16px 34px rgba(23, 33, 47, 0.09);
    animation: cardPop 520ms ease both;
    transition: transform 180ms ease, box-shadow 180ms ease, border-color 180ms ease;
}

.insight-card:hover {
    transform: translateY(-4px);
    border-color: var(--weather-accent);
    box-shadow: 0 22px 44px rgba(23, 33, 47, 0.14);
}

.insight-icon {
    width: 42px;
    height: 42px;
    display: grid;
    place-items: center;
    flex: 0 0 auto;
    color: #fff;
    background: var(--weather-accent);
    border-radius: var(--radius);
    box-shadow: 0 14px 24px var(--weather-glow);
}

.insight-card span,
.hourly-card span {
    color: var(--muted);
    font-size: 0.78rem;
    font-weight: 900;
    text-transform: uppercase;
}

.insight-card strong {
    display: block;
    margin-top: 10px;
    color: var(--ink);
    font-size: 1.55rem;
    line-height: 1;
}

.insight-card p {
    margin: 8px 0 0;
    color: var(--muted);
    font-size: 0.82rem;
    font-weight: 700;
}

.insight-card.is-alert .insight-icon { background: var(--coral); }
.insight-card.is-watch .insight-icon { background: var(--amber); }
.insight-card.is-good .insight-icon { background: var(--green); }

.metrics-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
}

.metric-card,
.forecast-card,
.air-chip {
    background:
        linear-gradient(180deg, rgba(255, 255, 255, 0.98), rgba(247, 250, 252, 0.9)),
        var(--surface);
}

.hourly-section {
    min-width: 0;
    grid-column: 1 / -1;
    padding: 22px;
    overflow: hidden;
    background:
        linear-gradient(135deg, rgba(23, 33, 47, 0.96), rgba(18, 75, 80, 0.92)),
        var(--ink);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius);
    box-shadow: 0 24px 56px rgba(23, 33, 47, 0.18);
    animation: riseIn 720ms ease 140ms both;
}

.hourly-section .eyebrow,
.hourly-section h2,
.hourly-section #hourlySignal {
    color: #fff;
}

.hourly-section #hourlySignal {
    opacity: 0.72;
    font-size: 0.84rem;
    font-weight: 900;
}

.hourly-grid {
    display: grid;
    grid-template-columns: repeat(8, minmax(94px, 1fr));
    gap: 10px;
}

.hourly-card {
    min-height: 154px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    padding: 13px;
    color: #fff;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.12);
    border-radius: var(--radius);
    animation: cardPop 520ms ease both;
    animation-delay: var(--delay);
}

.hourly-card img {
    width: 50px;
    height: 50px;
    object-fit: contain;
    filter: drop-shadow(0 12px 16px rgba(0, 0, 0, 0.24));
}

.hourly-card strong {
    font-size: 1.5rem;
    line-height: 1;
}

.hourly-card p {
    margin: 0;
    color: rgba(255, 255, 255, 0.68);
    font-size: 0.78rem;
    font-weight: 800;
}

.forecast-section,
.air-section,
.mail-alerts-panel {
    background:
        linear-gradient(135deg, rgba(255, 255, 255, 0.96), var(--weather-panel)),
        var(--surface);
}

.contact-section {
    position: relative;
    display: grid;
    grid-template-columns: minmax(260px, 0.86fr) minmax(360px, 1.14fr);
    gap: 18px;
    margin-top: 16px;
    padding: 22px;
    overflow: hidden;
    color: #fff;
    background:
        radial-gradient(circle at 16% 18%, rgba(94, 234, 212, 0.28), transparent 32%),
        radial-gradient(circle at 88% 82%, rgba(250, 204, 21, 0.18), transparent 28%),
        linear-gradient(135deg, rgba(8, 18, 32, 0.96), rgba(18, 75, 80, 0.92)),
        var(--ink);
    border: 1px solid rgba(125, 211, 252, 0.18);
    border-radius: var(--radius);
    box-shadow: 0 24px 56px rgba(8, 18, 32, 0.22);
    animation: riseIn 680ms ease 160ms both;
}

.contact-section::before {
    content: "";
    position: absolute;
    inset: 0;
    pointer-events: none;
    background:
        linear-gradient(rgba(125, 211, 252, 0.06) 1px, transparent 1px),
        linear-gradient(90deg, rgba(125, 211, 252, 0.06) 1px, transparent 1px);
    background-size: 48px 48px;
    mask-image: linear-gradient(135deg, rgba(0, 0, 0, 0.86), transparent 78%);
}

.contact-copy,
.contact-form {
    position: relative;
    z-index: 1;
}

.contact-copy {
    min-width: 0;
    display: grid;
    align-content: center;
}

.contact-copy .eyebrow {
    color: #5eead4;
}

.contact-copy h2 {
    max-width: 520px;
    margin-bottom: 10px;
    color: #fff;
    font-size: clamp(2rem, 4vw, 3.15rem);
    line-height: 0.98;
}

.contact-copy p {
    max-width: 520px;
    margin-bottom: 18px;
    color: rgba(237, 247, 255, 0.74);
    font-weight: 750;
    line-height: 1.58;
}

.contact-status-row {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
}

.contact-status-row span {
    min-height: 36px;
    display: inline-flex;
    align-items: center;
    gap: 7px;
    padding: 0 11px;
    color: #eaffff;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(125, 211, 252, 0.16);
    border-radius: var(--radius);
    font-size: 0.78rem;
    font-weight: 900;
}

.contact-status-row svg {
    width: 16px;
    height: 16px;
    color: #5eead4;
}

.contact-form {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 12px;
    padding: 16px;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.13);
    border-radius: var(--radius);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.12);
    backdrop-filter: blur(18px);
}

.contact-field {
    min-width: 0;
    display: grid;
    gap: 7px;
}

.contact-field > span {
    color: rgba(237, 247, 255, 0.72);
    font-size: 0.72rem;
    font-weight: 900;
    letter-spacing: 0;
    text-transform: uppercase;
}

.contact-field-wide,
.contact-form-footer,
.contact-status {
    grid-column: 1 / -1;
}

.contact-input {
    min-height: 56px;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 0 13px;
    color: #f8fbff;
    background: rgba(255, 255, 255, 0.09);
    border: 1px solid rgba(255, 255, 255, 0.16);
    border-radius: var(--radius);
    transition: border-color 180ms ease, background-color 180ms ease, box-shadow 180ms ease;
}

.contact-input:focus-within {
    border-color: rgba(94, 234, 212, 0.68);
    background: rgba(255, 255, 255, 0.13);
    box-shadow: 0 0 0 4px rgba(94, 234, 212, 0.12);
}

.contact-input svg {
    flex: 0 0 auto;
    width: 19px;
    height: 19px;
    color: #5eead4;
}

.contact-input input,
.contact-input textarea {
    width: 100%;
    min-width: 0;
    border: 0;
    outline: 0;
    color: #fff;
    background: transparent;
    font: inherit;
    font-weight: 800;
}

.contact-input input::placeholder,
.contact-input textarea::placeholder {
    color: rgba(237, 247, 255, 0.42);
}

.contact-message-input {
    min-height: 142px;
    align-items: flex-start;
    padding-top: 14px;
    padding-bottom: 14px;
}

.contact-message-input svg {
    margin-top: 3px;
}

.contact-input textarea {
    min-height: 112px;
    max-height: 240px;
    resize: vertical;
    line-height: 1.5;
}

.contact-form-footer {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 12px;
}

.contact-form-footer p {
    min-width: 0;
    margin: 0;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    color: rgba(237, 247, 255, 0.7);
    font-size: 0.82rem;
    font-weight: 850;
}

.contact-form-footer p svg {
    flex: 0 0 auto;
    width: 17px;
    height: 17px;
    color: #facc15;
}

.contact-submit {
    flex: 0 0 auto;
    min-width: 166px;
}

.contact-status {
    margin: 0;
    padding: 10px 12px;
    color: #cffafe;
    background: rgba(14, 165, 233, 0.12);
    border: 1px solid rgba(125, 211, 252, 0.2);
    border-radius: 6px;
    font-size: 0.86rem;
    font-weight: 850;
}

.contact-status.is-success {
    color: #dcfce7;
    background: rgba(34, 197, 94, 0.16);
    border-color: rgba(134, 239, 172, 0.28);
}

.contact-status.is-error {
    color: #ffe4e6;
    background: rgba(244, 63, 94, 0.16);
    border-color: rgba(253, 164, 175, 0.28);
}

.site-footer {
    width: min(1180px, calc(100% - 32px));
    margin: 26px auto 22px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 14px;
    color: var(--muted);
    font-size: 0.86rem;
    font-weight: 700;
    animation: riseIn 620ms ease 240ms both;
}

.footer-copy {
    display: flex;
    flex-wrap: wrap;
    gap: 8px 16px;
}

.susnata-codes-link {
    position: relative;
    min-height: 46px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    padding: 0 16px;
    overflow: hidden;
    color: #fff;
    background: linear-gradient(135deg, var(--teal), var(--blue) 54%, var(--coral));
    border-radius: var(--radius);
    box-shadow: 0 16px 32px rgba(37, 99, 235, 0.24);
    font-size: 0.86rem;
    font-weight: 900;
    transition: transform 180ms ease, box-shadow 180ms ease;
}

.susnata-codes-link::before {
    content: "";
    position: absolute;
    inset: 0;
    background: linear-gradient(110deg, transparent 0 32%, rgba(255, 255, 255, 0.34) 46%, transparent 60%);
    transform: translateX(-120%);
    animation: buttonShine 4.6s ease-in-out infinite;
}

.susnata-codes-link:hover {
    box-shadow: 0 20px 38px rgba(37, 99, 235, 0.32);
}

.susnata-codes-link > * {
    position: relative;
    z-index: 1;
}

.login-backdrop {
    position: fixed;
    inset: 0;
    z-index: 120;
    background: rgba(23, 33, 47, 0.34);
    opacity: 0;
    transition: opacity 200ms ease;
    backdrop-filter: blur(4px);
}

.login-backdrop.is-open {
    opacity: 1;
}

.signup-login {
    position: fixed;
    top: 40%;
    left: 50%;
    z-index: 130;
    width: min(600px, calc(100% - 32px));
    min-height: 230px;
    display: grid;
    align-items: center;
    background-color: rgb(46, 70, 121);
    border: 4px solid #fff;
    box-shadow: 0 0 5px 0 rgba(0, 0, 0, 1);
    opacity: 0;
    transform: translate(-50%, -50%);
    transition: top 200ms ease, opacity 200ms ease;
}

.signup-login.is-open {
    top: 50%;
    opacity: 1;
}

.signupForm {
    width: 100%;
    position: relative;
    margin: auto;
    padding: 20px;
    text-align: center;
}

.signupForm h2 {
    margin: 0 0 24px;
    color: #fff;
    font-size: 2rem;
    font-weight: 800;
    letter-spacing: 0;
}

.signupForm form span {
    display: inline-flex;
    justify-content: center;
    max-width: 100%;
}

.signupForm input {
    min-height: 60px;
    border: 0;
    font-size: 1.12rem;
    padding: 18px;
    outline: 0;
}

.signupForm input[type="email"] {
    width: min(350px, 100%);
    color: var(--ink);
    background: #fff;
}

.signupForm input[type="submit"] {
    width: 120px;
    margin-left: -4px;
    color: #fff;
    background-color: rgb(63, 97, 179);
    cursor: pointer;
    font-weight: 800;
}

.signupForm input[type="submit"]:hover {
    background-color: rgb(74, 112, 205);
}

.signup-close {
    position: absolute;
    top: 8px;
    right: 10px;
    z-index: 5;
    width: 34px;
    height: 34px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #fff;
    background: transparent;
    border: 0;
    font-size: 2rem;
    font-weight: 900;
    line-height: 1;
    cursor: pointer;
}

.login-status {
    min-height: 20px;
    margin: 14px 0 0;
    color: rgba(255, 255, 255, 0.84);
    font-size: 0.86rem;
    font-weight: 800;
}

.earthquake-overlay {
    position: fixed;
    inset: 0;
    z-index: 200;
    background: #0a0a0a;
}

.earthquake-overlay iframe {
    width: 100%;
    height: 100%;
    display: block;
    border: 0;
    background: #0a0a0a;
}

.earthquake-close-button {
    position: absolute;
    top: 50%;
    right: 20px;
    width: 44px;
    height: 44px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    color: #888;
    background: rgba(0, 0, 0, 0.9);
    border: 1px solid #222;
    border-radius: 0;
    cursor: pointer;
    transform: translateY(-50%);
    transition: color 160ms ease, border-color 160ms ease, background-color 160ms ease;
}

.earthquake-close-button:hover {
    color: #fff;
    border-color: #333;
    background: rgba(17, 17, 17, 0.96);
}

.sr-only {
    position: absolute;
    width: 1px;
    height: 1px;
    padding: 0;
    margin: -1px;
    overflow: hidden;
    clip: rect(0, 0, 0, 0);
    white-space: nowrap;
    border: 0;
}

[hidden] {
    display: none !important;
}

.is-busy {
    pointer-events: none;
    opacity: 0.72;
}

@media (max-width: 980px) {
    .search-toolbar,
    .mail-alerts-panel,
    .weather-dashboard {
        grid-template-columns: 1fr;
    }

    .mail-alerts-form {
        grid-template-columns: 1fr 1fr;
    }

    .mail-alerts-preferences {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }

    .forecast-grid {
        grid-template-columns: repeat(3, minmax(0, 1fr));
    }

    .hourly-grid {
        grid-template-columns: repeat(4, minmax(0, 1fr));
    }

    .air-section {
        flex-direction: column;
    }
}

@media (max-width: 760px) {
    .topbar {
        align-items: stretch;
        flex-direction: column;
    }

    .topbar-actions {
        width: 100%;
        display: grid;
        grid-template-columns: 44px 44px 88px minmax(44px, 0.72fr) minmax(0, 1fr);
        justify-content: start;
        flex-wrap: initial;
    }

    .contact-menu {
        grid-column: auto;
        width: 100%;
        min-width: 0;
    }

    .menu-button {
        min-width: 0;
    }

    .header-blog-link {
        width: 100%;
        padding: 0;
    }

    .header-blog-link span {
        display: none;
    }

    .segmented-control {
        width: 88px;
    }

    .search-form {
        grid-template-columns: 1fr;
    }

    .mail-alerts-form {
        grid-template-columns: 1fr;
    }

    .mail-alerts-preferences {
        grid-template-columns: 1fr;
    }

    .primary-button,
    .secondary-button {
        width: 100%;
    }

    h1 {
        font-size: 2.25rem;
    }

    .current-copy h2 {
        font-size: 1.55rem;
        line-height: 1.15;
    }

    .temperature-block {
        align-items: flex-start;
        flex-direction: column;
    }

    .temperature-block strong,
    .temperature-block span {
        text-align: left;
    }

    .temperature-block strong {
        font-size: 3.2rem;
    }

    .metrics-grid,
    .forecast-grid,
    .insights-strip,
    .air-components {
        grid-template-columns: 1fr;
    }

    .hourly-grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }

    .site-footer {
        align-items: stretch;
        flex-direction: column;
    }

    .susnata-codes-link {
        width: 100%;
    }
}

@media (max-width: 480px) {
    .topbar,
    .dashboard,
    .site-footer {
        width: min(100% - 20px, 1180px);
    }

    .search-toolbar,
    .mail-alerts-panel,
    .contact-section,
    .current-panel,
    .forecast-section,
    .air-section {
        padding: 16px;
    }

    .metrics-grid,
    .forecast-grid,
    .insights-strip,
    .hourly-grid,
    .air-components {
        grid-template-columns: 1fr;
    }

    .weather-orbit {
        right: -18px;
        bottom: -18px;
        width: 124px;
        height: 124px;
    }

    .topbar-actions {
        display: grid;
        grid-template-columns: 44px 44px 88px 44px minmax(0, 1fr);
        align-items: center;
        justify-content: start;
    }

    .signup-login {
        width: min(100% - 20px, 600px);
        min-height: 250px;
    }

    .signupForm h2 {
        font-size: 1.55rem;
    }

    .signupForm form span {
        display: grid;
        grid-template-columns: 1fr;
        gap: 10px;
    }

    .signupForm input[type="email"],
    .signupForm input[type="submit"] {
        width: 100%;
        margin-left: 0;
    }

    .mail-alerts-meta {
        display: grid;
        grid-template-columns: 1fr;
    }

    .contact-menu {
        grid-column: auto;
        min-width: 0;
    }

    .contact-panel {
        left: 0;
        right: auto;
        width: 100%;
    }
}

/* Cinematic command-center redesign */
body {
    color: #edf7ff;
    background:
        radial-gradient(circle at 12% 18%, rgba(14, 165, 233, 0.28), transparent 30%),
        radial-gradient(circle at 78% 8%, rgba(250, 204, 21, 0.2), transparent 24%),
        radial-gradient(circle at 88% 78%, rgba(220, 74, 54, 0.22), transparent 28%),
        linear-gradient(145deg, #07111f 0%, #0b1c2d 38%, #122635 66%, #07111f 100%);
}

.weather-effects {
    background:
        linear-gradient(120deg, rgba(37, 99, 235, 0.08), transparent 32%, rgba(20, 184, 166, 0.12)),
        linear-gradient(180deg, rgba(255, 255, 255, 0.03), transparent);
}

.weather-effects::before {
    opacity: 0.86;
    background:
        linear-gradient(110deg, transparent 0 24%, rgba(255, 255, 255, 0.24) 36%, transparent 48%),
        linear-gradient(145deg, rgba(14, 165, 233, 0.18), transparent 42%, rgba(245, 158, 11, 0.16));
}

.weather-effects::after {
    content: "";
    position: absolute;
    inset: 0;
    background-image:
        linear-gradient(rgba(148, 163, 184, 0.12) 1px, transparent 1px),
        linear-gradient(90deg, rgba(148, 163, 184, 0.1) 1px, transparent 1px);
    background-size: 72px 72px;
    mask-image: linear-gradient(180deg, rgba(0, 0, 0, 0.72), transparent 86%);
    opacity: 0.48;
    animation: gridDrift 18s linear infinite;
}

.rain-field {
    opacity: 0.33;
    background-image: repeating-linear-gradient(
        118deg,
        rgba(125, 211, 252, 0.26) 0 2px,
        transparent 2px 18px
    );
}

.rain-field-two {
    opacity: 0.2;
}

.sky-ribbon {
    filter: blur(34px);
    opacity: 0.86;
}

.ribbon-one {
    background: linear-gradient(90deg, transparent, rgba(34, 211, 238, 0.36), rgba(245, 158, 11, 0.28), transparent);
}

.ribbon-two {
    background: linear-gradient(90deg, transparent, rgba(37, 99, 235, 0.32), rgba(220, 74, 54, 0.22), rgba(20, 184, 166, 0.28), transparent);
}

.wind-streams span {
    height: 3px;
    background: linear-gradient(90deg, transparent, rgba(125, 211, 252, 0.38), rgba(255, 255, 255, 0.18), transparent);
    box-shadow: 0 0 18px rgba(125, 211, 252, 0.22);
}

.float-icon {
    color: rgba(125, 211, 252, 0.2);
    opacity: 0.86;
}

.float-rain {
    color: rgba(45, 212, 191, 0.18);
}

.float-bolt {
    color: rgba(250, 204, 21, 0.2);
}

.topbar {
    overflow: visible;
    color: #edf7ff;
    background:
        linear-gradient(135deg, rgba(8, 18, 32, 0.88), rgba(12, 30, 48, 0.72)),
        rgba(8, 18, 32, 0.78);
    border-color: rgba(125, 211, 252, 0.22);
    box-shadow: 0 20px 52px rgba(0, 0, 0, 0.34), inset 0 1px 0 rgba(255, 255, 255, 0.08);
}

.topbar::before {
    content: "";
    position: absolute;
    inset: 0;
    background: linear-gradient(100deg, transparent, rgba(125, 211, 252, 0.16), transparent);
    transform: translateX(-120%);
    animation: glassSweep 6s ease-in-out infinite;
    border-radius: inherit;
    pointer-events: none;
}

.topbar > * {
    position: relative;
    z-index: 1;
}

.brand-name {
    color: #f8fbff;
    font-size: 1.08rem;
}

.brand-owner {
    color: #a9b8ca;
}

.brand-mark {
    background: linear-gradient(135deg, #0f766e, #0ea5e9 62%, #f59e0b);
    box-shadow: 0 0 28px rgba(45, 212, 191, 0.36);
}

.icon-button,
.secondary-button,
.header-blog-link,
.unit-button,
.recent-chip {
    color: #eaf6ff;
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(148, 163, 184, 0.24);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08);
}

.icon-button:hover,
.secondary-button:hover,
.recent-chip:hover,
.header-blog-link:hover {
    color: #ffffff;
    border-color: rgba(45, 212, 191, 0.56);
    background: rgba(15, 118, 110, 0.34);
    box-shadow: 0 16px 34px rgba(20, 184, 166, 0.18);
}

.primary-button {
    background: linear-gradient(135deg, #0f766e, #0ea5e9 64%, #f59e0b);
    box-shadow: 0 20px 42px rgba(14, 165, 233, 0.28);
}

.primary-button:hover {
    background: linear-gradient(135deg, #0b665f, #0284c7 64%, #d97706);
}

.segmented-control {
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(148, 163, 184, 0.24);
}

.unit-button.is-active {
    color: #081220;
    background: #f8fbff;
    box-shadow: 0 10px 24px rgba(255, 255, 255, 0.16);
}

.header-blog-link {
    color: #ccfbf1;
}

.menu-button {
    min-width: 132px;
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(45, 212, 191, 0.36);
}

.contact-panel {
    color: #edf7ff;
    background: rgba(8, 18, 32, 0.94);
    border-color: rgba(125, 211, 252, 0.22);
    box-shadow: 0 24px 60px rgba(0, 0, 0, 0.38);
}

.contact-panel a,
.contact-panel button {
    color: #edf7ff;
}

.contact-panel a:hover,
.contact-panel button:hover {
    color: #ccfbf1;
    background: rgba(20, 184, 166, 0.14);
}

.dashboard {
    margin-top: 26px;
}

.search-toolbar {
    grid-template-columns: minmax(0, 1fr) minmax(320px, 0.88fr);
    align-items: center;
    min-height: 390px;
    padding: 30px;
    isolation: isolate;
    background:
        radial-gradient(circle at 26% 26%, rgba(59, 130, 246, 0.26), transparent 34%),
        radial-gradient(circle at 76% 22%, rgba(20, 184, 166, 0.22), transparent 30%),
        linear-gradient(135deg, rgba(8, 18, 32, 0.96), rgba(15, 35, 54, 0.88) 52%, rgba(11, 28, 45, 0.96)),
        #081220;
    border-color: rgba(125, 211, 252, 0.22);
    box-shadow: 0 34px 88px rgba(0, 0, 0, 0.38), inset 0 1px 0 rgba(255, 255, 255, 0.08);
}

.search-toolbar::before {
    inset: 0;
    height: auto;
    background:
        linear-gradient(90deg, rgba(125, 211, 252, 0.1) 1px, transparent 1px),
        linear-gradient(rgba(125, 211, 252, 0.08) 1px, transparent 1px);
    background-size: 48px 48px;
    opacity: 0.4;
    animation: gridDrift 16s linear infinite;
}

.search-toolbar::after {
    content: "";
    position: absolute;
    inset: -1px;
    z-index: 0;
    background:
        linear-gradient(115deg, transparent 0 18%, rgba(255, 255, 255, 0.16) 34%, transparent 48%),
        radial-gradient(circle at 70% 50%, rgba(250, 204, 21, 0.14), transparent 30%);
    opacity: 0.82;
    animation: skySweep 11s ease-in-out infinite;
}

.search-title-block h1 {
    max-width: 8ch;
    color: #ffffff;
    font-size: 4.8rem;
    line-height: 0.92;
    text-shadow: 0 18px 54px rgba(14, 165, 233, 0.32);
}

.search-title-block .eyebrow,
.mail-alerts-panel .eyebrow,
.hourly-section .eyebrow,
.forecast-section .eyebrow,
.air-section .eyebrow {
    color: #5eead4;
}

.live-brief-pills {
    gap: 10px;
    margin-top: 22px;
}

.live-brief-pills > span,
.current-live-row span {
    min-height: 40px;
    padding: 0 13px;
    color: #ddfffb;
    background: rgba(8, 18, 32, 0.58);
    border-color: rgba(94, 234, 212, 0.26);
    box-shadow: 0 14px 34px rgba(20, 184, 166, 0.12), inset 0 1px 0 rgba(255, 255, 255, 0.08);
    backdrop-filter: blur(12px);
}

.hero-visual {
    position: relative;
    min-height: 290px;
    display: grid;
    place-items: center;
}

.radar-rings {
    position: absolute;
    inset: 16px;
    display: grid;
    place-items: center;
}

.radar-rings span {
    position: absolute;
    width: var(--size);
    height: var(--size);
    border: 1px solid rgba(125, 211, 252, 0.22);
    border-radius: 50%;
    box-shadow: inset 0 0 32px rgba(14, 165, 233, 0.08), 0 0 32px rgba(20, 184, 166, 0.08);
    animation: radarPulse 3.8s ease-in-out infinite;
}

.radar-rings span:nth-child(1) {
    --size: 118px;
}

.radar-rings span:nth-child(2) {
    --size: 192px;
    animation-delay: 0.5s;
}

.radar-rings span:nth-child(3) {
    --size: 262px;
    animation-delay: 1s;
}

.radar-sweep {
    position: absolute;
    width: 260px;
    height: 260px;
    border-radius: 50%;
    background: conic-gradient(from 0deg, rgba(94, 234, 212, 0.42), rgba(94, 234, 212, 0.06) 18%, transparent 24% 100%);
    mask-image: radial-gradient(circle, transparent 0 20%, #000 21% 100%);
    animation: radarSweep 4.4s linear infinite;
}

.radar-core {
    position: relative;
    z-index: 1;
    width: 112px;
    height: 112px;
    display: grid;
    place-items: center;
    color: #07111f;
    background: linear-gradient(135deg, #f8fbff, #5eead4 55%, #facc15);
    border: 1px solid rgba(255, 255, 255, 0.42);
    border-radius: 50%;
    box-shadow: 0 0 48px rgba(94, 234, 212, 0.42), 0 24px 60px rgba(0, 0, 0, 0.26);
    animation: coreFloat 4s ease-in-out infinite;
}

.radar-core svg {
    width: 48px;
    height: 48px;
    stroke-width: 2.1;
}

.signal-card {
    position: absolute;
    z-index: 2;
    min-width: 116px;
    padding: 12px;
    color: #edf7ff;
    background: rgba(8, 18, 32, 0.72);
    border: 1px solid rgba(125, 211, 252, 0.28);
    border-radius: var(--radius);
    box-shadow: 0 22px 42px rgba(0, 0, 0, 0.28), inset 0 1px 0 rgba(255, 255, 255, 0.08);
    backdrop-filter: blur(14px);
}

.signal-card span {
    display: block;
    color: #9fb2c7;
    font-size: 0.72rem;
    font-weight: 900;
    text-transform: uppercase;
}

.signal-card strong {
    display: block;
    margin-top: 5px;
    color: #ffffff;
    font-size: 1.15rem;
}

.signal-card-one {
    top: 28px;
    left: 22px;
}

.signal-card-two {
    right: 18px;
    bottom: 34px;
}

.storm-dot {
    position: absolute;
    z-index: 2;
    width: 11px;
    height: 11px;
    background: #facc15;
    border-radius: 50%;
    box-shadow: 0 0 24px rgba(250, 204, 21, 0.76);
    animation: stormPing 2.8s ease-in-out infinite;
}

.storm-dot-one {
    top: 76px;
    right: 98px;
}

.storm-dot-two {
    left: 88px;
    bottom: 86px;
    background: #5eead4;
    box-shadow: 0 0 24px rgba(94, 234, 212, 0.72);
    animation-delay: 0.8s;
}

.storm-dot-three {
    right: 154px;
    bottom: 118px;
    background: #fb7185;
    box-shadow: 0 0 24px rgba(251, 113, 133, 0.72);
    animation-delay: 1.4s;
}

.search-form {
    grid-column: 1 / -1;
    position: relative;
    z-index: 2;
    padding: 10px;
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(125, 211, 252, 0.24);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08), 0 24px 52px rgba(0, 0, 0, 0.22);
    backdrop-filter: blur(14px);
}

.input-control {
    color: #edf7ff;
    background: rgba(255, 255, 255, 0.09);
    border-color: rgba(148, 163, 184, 0.24);
}

.input-control svg {
    color: #5eead4;
}

.input-control input {
    color: #f8fbff;
}

.input-control input::placeholder {
    color: #9fb2c7;
}

.mail-alerts-panel {
    color: #edf7ff;
    background:
        radial-gradient(circle at 15% 15%, rgba(20, 184, 166, 0.18), transparent 32%),
        linear-gradient(135deg, rgba(8, 18, 32, 0.9), rgba(11, 28, 45, 0.76)),
        #081220;
    border-color: rgba(125, 211, 252, 0.2);
    box-shadow: 0 24px 58px rgba(0, 0, 0, 0.3);
}

.mail-alerts-panel h2,
.section-heading h2,
.air-section h2 {
    color: #f8fbff;
}

.mail-alerts-meta span {
    color: #dffdfa;
    background: rgba(94, 234, 212, 0.12);
    border-color: rgba(94, 234, 212, 0.24);
}

.mail-toggle,
.mail-field {
    color: #edf7ff;
    background: rgba(255, 255, 255, 0.09);
    border-color: rgba(125, 211, 252, 0.18);
}

.mail-field span {
    color: #9fb2c7;
}

.mail-field input,
.mail-field select {
    color: #f8fbff;
}

.mail-field select option {
    color: #17212f;
}

.mail-server-status.is-success {
    color: #b7fff6;
    background: rgba(20, 184, 166, 0.12);
    border-color: rgba(94, 234, 212, 0.28);
}

.mail-server-status.is-warning {
    color: #fde68a;
    background: rgba(250, 204, 21, 0.1);
    border-color: rgba(250, 204, 21, 0.24);
}

.weather-dashboard {
    grid-template-columns: minmax(380px, 1.08fr) minmax(430px, 0.92fr);
    gap: 16px;
}

.current-panel {
    min-height: 470px;
    background:
        radial-gradient(circle at 20% 20%, rgba(250, 204, 21, 0.16), transparent 26%),
        radial-gradient(circle at 78% 74%, rgba(94, 234, 212, 0.24), transparent 28%),
        linear-gradient(135deg, rgba(5, 12, 24, 0.98), var(--weather-accent) 58%, var(--weather-accent-2)),
        #07111f;
    border: 1px solid rgba(125, 211, 252, 0.18);
    box-shadow: 0 32px 86px rgba(0, 0, 0, 0.36), 0 24px 84px var(--weather-glow);
}

.current-panel::before {
    width: 112%;
    height: 112%;
    border-color: rgba(125, 211, 252, 0.22);
    animation: orbitSpin 26s linear infinite;
}

.current-panel::after {
    border-color: rgba(255, 255, 255, 0.12);
    background:
        linear-gradient(115deg, rgba(255, 255, 255, 0.16), transparent 38%),
        repeating-linear-gradient(90deg, rgba(255, 255, 255, 0.05) 0 1px, transparent 1px 42px);
}

.current-copy h2 {
    max-width: 9ch;
    font-size: 3.75rem;
    line-height: 0.95;
}

.temperature-block img {
    width: 102px;
    height: 102px;
    filter: drop-shadow(0 24px 32px rgba(0, 0, 0, 0.36));
}

.temperature-block strong {
    text-shadow: 0 18px 42px rgba(255, 255, 255, 0.2);
}

.weather-orbit {
    width: 178px;
    height: 178px;
    border-color: rgba(125, 211, 252, 0.26);
    box-shadow: inset 0 0 48px rgba(125, 211, 252, 0.08);
}

.insight-card,
.metric-card,
.forecast-card,
.air-chip {
    color: #edf7ff;
    background:
        linear-gradient(145deg, rgba(255, 255, 255, 0.12), rgba(255, 255, 255, 0.055)),
        rgba(8, 18, 32, 0.72);
    border-color: rgba(125, 211, 252, 0.18);
    box-shadow: 0 22px 46px rgba(0, 0, 0, 0.26), inset 0 1px 0 rgba(255, 255, 255, 0.06);
    backdrop-filter: blur(14px);
}

.insight-card:hover,
.metric-card:hover,
.forecast-card:hover,
.air-chip:hover {
    transform: translateY(-6px);
    border-color: rgba(94, 234, 212, 0.54);
    box-shadow: 0 28px 64px rgba(0, 0, 0, 0.34), 0 0 34px rgba(94, 234, 212, 0.14);
}

.insight-card span,
.metric-label span,
.forecast-pop,
.forecast-description,
.metric-note,
.air-chip span:first-child,
.hourly-card span {
    color: #9fb2c7;
}

.insight-card strong,
.metric-value,
.forecast-day,
.forecast-high,
.air-chip span:last-child {
    color: #f8fbff;
}

.hourly-section {
    background:
        radial-gradient(circle at 20% 10%, rgba(94, 234, 212, 0.18), transparent 28%),
        radial-gradient(circle at 82% 30%, rgba(250, 204, 21, 0.14), transparent 26%),
        linear-gradient(135deg, rgba(5, 12, 24, 0.98), rgba(12, 30, 48, 0.94)),
        #07111f;
    border-color: rgba(125, 211, 252, 0.18);
}

.hourly-card {
    background: rgba(255, 255, 255, 0.09);
    border-color: rgba(125, 211, 252, 0.18);
}

.forecast-section,
.air-section {
    color: #edf7ff;
    background:
        linear-gradient(145deg, rgba(255, 255, 255, 0.11), rgba(255, 255, 255, 0.06)),
        rgba(8, 18, 32, 0.72);
    border-color: rgba(125, 211, 252, 0.18);
    box-shadow: 0 24px 56px rgba(0, 0, 0, 0.26);
}

.site-footer {
    color: #a9b8ca;
}

.susnata-codes-link {
    background: linear-gradient(135deg, #0f766e, #0ea5e9 48%, #f59e0b);
    box-shadow: 0 18px 42px rgba(14, 165, 233, 0.28);
}

.icon-button.is-profile {
    width: auto;
    min-width: 44px;
    padding: 4px;
    color: #081220;
    background: linear-gradient(135deg, #f8fbff, #5eead4 58%, #facc15);
    border-color: rgba(255, 255, 255, 0.36);
}

.header-profile-photo,
.header-profile-initials {
    width: 36px;
    height: 36px;
    display: grid;
    place-items: center;
    border-radius: 50%;
}

.header-profile-photo {
    object-fit: cover;
}

.header-profile-initials {
    color: #07111f;
    background: rgba(255, 255, 255, 0.82);
    font-size: 0.82rem;
    font-weight: 950;
}

.signup-login.auth-panel {
    top: 50%;
    width: min(920px, calc(100% - 32px));
    min-height: 500px;
    display: grid;
    grid-template-columns: minmax(240px, 0.84fr) minmax(320px, 1.16fr);
    align-items: stretch;
    overflow: hidden;
    color: #edf7ff;
    background:
        linear-gradient(135deg, rgba(8, 18, 32, 0.98), rgba(12, 30, 48, 0.96)),
        #081220;
    border: 1px solid rgba(125, 211, 252, 0.24);
    border-radius: var(--radius);
    box-shadow: 0 34px 88px rgba(0, 0, 0, 0.48), 0 0 0 1px rgba(255, 255, 255, 0.04) inset;
    opacity: 0;
    transform: translate(-50%, -48%) scale(0.98);
    transition: opacity 200ms ease, transform 200ms ease;
}

.signup-login.auth-panel.is-open {
    top: 50%;
    opacity: 1;
    transform: translate(-50%, -50%) scale(1);
}

.auth-visual {
    position: relative;
    display: grid;
    place-items: center;
    min-height: 100%;
    overflow: hidden;
    background:
        linear-gradient(90deg, rgba(125, 211, 252, 0.08) 1px, transparent 1px),
        linear-gradient(rgba(125, 211, 252, 0.06) 1px, transparent 1px),
        radial-gradient(circle at 50% 42%, rgba(94, 234, 212, 0.18), transparent 44%);
    background-size: 42px 42px, 42px 42px, auto;
}

.auth-visual::before,
.auth-visual::after {
    content: "";
    position: absolute;
    inset: 18%;
    border: 1px solid rgba(94, 234, 212, 0.22);
    border-radius: 50%;
    animation: orbitSpin 18s linear infinite;
}

.auth-visual::after {
    inset: 30%;
    border-color: rgba(250, 204, 21, 0.22);
    animation-duration: 12s;
    animation-direction: reverse;
}

.auth-visual > i {
    position: relative;
    z-index: 2;
    width: 96px;
    height: 96px;
    display: grid;
    place-items: center;
    color: #07111f;
    background: linear-gradient(135deg, #f8fbff, #5eead4 58%, #facc15);
    border-radius: 50%;
    box-shadow: 0 0 54px rgba(94, 234, 212, 0.34), 0 24px 60px rgba(0, 0, 0, 0.3);
}

.auth-visual > i svg {
    width: 44px;
    height: 44px;
}

.auth-orbit,
.auth-glow {
    position: absolute;
    border-radius: 999px;
}

.auth-orbit {
    width: 9px;
    height: 9px;
    background: #5eead4;
    border-radius: 3px;
    box-shadow: 0 0 24px rgba(94, 234, 212, 0.72);
    animation: stormPing 3s ease-in-out infinite;
}

.auth-orbit-one {
    top: 28%;
    right: 28%;
}

.auth-orbit-two {
    left: 26%;
    bottom: 28%;
    background: #facc15;
    box-shadow: 0 0 24px rgba(250, 204, 21, 0.72);
    animation-delay: 1s;
}

.auth-glow {
    inset: auto 14% 11% 14%;
    height: 2px;
    background: linear-gradient(90deg, transparent, rgba(94, 234, 212, 0.6), transparent);
}

.signupForm.auth-card {
    display: grid;
    align-content: center;
    gap: 16px;
    padding: 34px;
    text-align: left;
    background:
        linear-gradient(115deg, rgba(255, 255, 255, 0.08), transparent 36%),
        rgba(8, 18, 32, 0.7);
}

.auth-heading h2 {
    margin: 0;
    color: #f8fbff;
    font-size: 2.15rem;
    line-height: 1.05;
}

.auth-heading p:last-child {
    margin: 10px 0 0;
    color: #9fb2c7;
    font-weight: 700;
    line-height: 1.5;
}

.auth-mode-toggle {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 6px;
    padding: 5px;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(125, 211, 252, 0.16);
    border-radius: var(--radius);
}

.auth-mode-button {
    min-height: 42px;
    color: #9fb2c7;
    background: transparent;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 900;
}

.auth-mode-button.is-active {
    color: #07111f;
    background: #5eead4;
    box-shadow: 0 12px 26px rgba(94, 234, 212, 0.2);
}

.auth-form {
    display: grid;
    gap: 10px;
}

.auth-field {
    display: grid;
    gap: 7px;
}

.auth-field span {
    color: #9fb2c7;
    font-size: 0.74rem;
    font-weight: 900;
    text-transform: uppercase;
}

.signupForm .auth-field input {
    width: 100%;
    min-height: 54px;
    padding: 0 14px;
    color: #f8fbff;
    background: rgba(255, 255, 255, 0.09);
    border: 1px solid rgba(125, 211, 252, 0.18);
    border-radius: var(--radius);
    font-size: 1rem;
    font-weight: 800;
}

.signupForm .auth-field input::placeholder {
    color: #9fb2c7;
}

.auth-submit,
.google-login-button {
    min-height: 52px;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 10px;
    border-radius: var(--radius);
    cursor: pointer;
    font-weight: 950;
}

.auth-submit {
    color: #07111f;
    background: linear-gradient(135deg, #5eead4, #0ea5e9 62%, #facc15);
    box-shadow: 0 18px 40px rgba(14, 165, 233, 0.26);
}

.auth-divider {
    display: grid;
    grid-template-columns: 1fr auto 1fr;
    align-items: center;
    gap: 10px;
    color: #9fb2c7;
    font-size: 0.76rem;
    font-weight: 900;
    text-transform: uppercase;
}

.auth-divider::before,
.auth-divider::after {
    content: "";
    height: 1px;
    background: rgba(125, 211, 252, 0.18);
}

.google-login-button {
    color: #edf7ff;
    background: rgba(255, 255, 255, 0.09);
    border: 1px solid rgba(125, 211, 252, 0.2);
}

.google-mark {
    width: 28px;
    height: 28px;
    display: grid;
    place-items: center;
    color: #07111f;
    background: #f8fbff;
    border-radius: 50%;
    font-weight: 950;
}

.profile-card {
    display: grid;
    grid-template-columns: auto minmax(0, 1fr) auto;
    align-items: center;
    gap: 14px;
    padding: 14px;
    background:
        linear-gradient(145deg, rgba(94, 234, 212, 0.14), rgba(14, 165, 233, 0.08)),
        rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(94, 234, 212, 0.24);
    border-radius: var(--radius);
}

.profile-card img {
    width: 58px;
    height: 58px;
    object-fit: cover;
    border-radius: 50%;
}

.profile-card span,
.profile-card small {
    display: block;
    color: #9fb2c7;
    font-weight: 800;
}

.profile-card strong {
    display: block;
    margin: 3px 0;
    color: #f8fbff;
    font-size: 1.1rem;
}

.profile-card button {
    min-height: 38px;
    padding: 0 12px;
    color: #07111f;
    background: #facc15;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 950;
}

.login-status {
    color: #b7fff6;
}

.mail-alerts-panel {
    grid-template-columns: minmax(260px, 0.72fr) minmax(0, 1.28fr);
    align-items: stretch;
    gap: 0;
    margin-top: 22px;
    padding: 0;
    isolation: isolate;
    background:
        linear-gradient(90deg, rgba(125, 211, 252, 0.08) 1px, transparent 1px),
        linear-gradient(rgba(125, 211, 252, 0.06) 1px, transparent 1px),
        linear-gradient(135deg, rgba(6, 16, 30, 0.98), rgba(10, 32, 48, 0.96)),
        #07111f;
    background-size: 56px 56px, 56px 56px, auto, auto;
    border-color: rgba(94, 234, 212, 0.24);
    box-shadow: 0 30px 76px rgba(0, 0, 0, 0.34), inset 0 1px 0 rgba(255, 255, 255, 0.06);
}

.mail-alerts-panel::before {
    content: "";
    position: absolute;
    inset: 0;
    z-index: -1;
    background:
        linear-gradient(115deg, transparent 0 28%, rgba(94, 234, 212, 0.14) 43%, transparent 58%),
        radial-gradient(circle at 78% 20%, rgba(250, 204, 21, 0.12), transparent 34%);
    animation: skySweep 12s ease-in-out infinite;
}

.mail-alerts-copy {
    min-height: 330px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    padding: 26px;
    border-right: 1px solid rgba(125, 211, 252, 0.16);
}

.mail-alerts-copy h2 {
    max-width: 9ch;
    color: #f8fbff;
    font-size: 2.65rem;
    line-height: 0.96;
}

.mail-alerts-meta {
    display: grid;
    grid-template-columns: 1fr;
}

.mail-alerts-meta span {
    justify-content: flex-start;
    min-height: 42px;
    color: #dffdfa;
    background: rgba(8, 18, 32, 0.56);
    border-color: rgba(94, 234, 212, 0.22);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.05);
}

.mail-alerts-form {
    align-content: center;
    padding: 24px;
    background: rgba(255, 255, 255, 0.035);
}

.mail-alerts-form .input-control,
.mail-toggle,
.mail-field {
    background: rgba(255, 255, 255, 0.08);
    border-color: rgba(125, 211, 252, 0.2);
}

.mail-alerts-status,
.mail-server-status {
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.04);
}

@keyframes radarSweep {
    to {
        transform: rotate(360deg);
    }
}

@keyframes radarPulse {
    0%,
    100% {
        opacity: 0.42;
        transform: scale(0.96);
    }
    50% {
        opacity: 1;
        transform: scale(1.04);
    }
}

@keyframes coreFloat {
    0%,
    100% {
        transform: translateY(0) scale(1);
    }
    50% {
        transform: translateY(-10px) scale(1.04);
    }
}

@keyframes stormPing {
    0%,
    100% {
        opacity: 0.46;
        transform: scale(0.82);
    }
    50% {
        opacity: 1;
        transform: scale(1.35);
    }
}

@keyframes glassSweep {
    0%,
    42% {
        transform: translateX(-120%);
    }
    70%,
    100% {
        transform: translateX(120%);
    }
}

@keyframes gridDrift {
    to {
        background-position: 72px 72px;
    }
}

@media (max-width: 980px) {
    .search-toolbar {
        grid-template-columns: 1fr;
        min-height: 0;
    }

    .search-form {
        grid-template-columns: 1fr 1fr;
    }

    .search-form .input-control {
        grid-column: 1 / -1;
    }

    .hero-visual {
        min-height: 270px;
    }

    .weather-dashboard {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 760px) {
    .topbar {
        gap: 18px;
        padding: 18px;
    }

    .brand-mark {
        width: 72px;
        height: 72px;
    }

    .brand-mark svg {
        width: 34px;
        height: 34px;
    }

    .brand-name {
        font-size: 1.55rem;
    }

    .brand-owner {
        font-size: 1rem;
    }

    .search-toolbar {
        padding: 26px;
    }

    .search-title-block h1 {
        max-width: 9ch;
        font-size: 3.55rem;
    }

    .hero-visual {
        min-height: 250px;
    }

    .radar-sweep {
        width: 226px;
        height: 226px;
    }

    .radar-rings span:nth-child(3) {
        --size: 228px;
    }

    .search-form {
        grid-template-columns: 1fr;
    }

    .current-panel {
        min-height: 440px;
    }

    .current-copy h2 {
        max-width: 10ch;
        font-size: 2.6rem;
    }

    .weather-orbit {
        width: 136px;
        height: 136px;
    }
}

@media (max-width: 480px) {
    .topbar {
        width: min(100% - 20px, 1180px);
    }

    .topbar-actions {
        grid-template-columns: 1fr 1fr 1.7fr 1fr;
        gap: 10px;
    }

    .contact-menu {
        grid-column: 1 / -1;
    }

    .menu-button {
        width: 100%;
        min-width: 0;
    }

    .icon-button,
    .primary-button,
    .secondary-button,
    .header-blog-link,
    .unit-button {
        min-height: 54px;
    }

    .search-toolbar {
        padding: 22px;
    }

    .search-title-block h1 {
        font-size: 3rem;
    }

    .live-brief-pills {
        display: grid;
        grid-template-columns: 1fr;
    }

    .hero-visual {
        min-height: 228px;
    }

    .radar-core {
        width: 88px;
        height: 88px;
    }

    .radar-core svg {
        width: 38px;
        height: 38px;
    }

    .radar-sweep {
        width: 194px;
        height: 194px;
    }

    .radar-rings span:nth-child(1) {
        --size: 92px;
    }

    .radar-rings span:nth-child(2) {
        --size: 148px;
    }

    .radar-rings span:nth-child(3) {
        --size: 196px;
    }

    .signal-card {
        min-width: 96px;
        padding: 10px;
    }

    .signal-card-one {
        top: 10px;
        left: 0;
    }

    .signal-card-two {
        right: 0;
        bottom: 10px;
    }

    .current-panel {
        min-height: 430px;
    }

    .temperature-block strong {
        font-size: 3.6rem;
    }
}

.smart-brief-panel {
    margin-top: 16px;
    padding: 18px;
    color: #edf7ff;
    background:
        radial-gradient(circle at 18% 18%, rgba(94, 234, 212, 0.16), transparent 32%),
        linear-gradient(135deg, rgba(8, 18, 32, 0.9), rgba(11, 28, 45, 0.76)),
        #081220;
    border: 1px solid rgba(125, 211, 252, 0.2);
    border-radius: var(--radius);
    box-shadow: 0 24px 58px rgba(0, 0, 0, 0.28);
    animation: riseIn 520ms ease both;
}

.smart-brief-panel .section-heading {
    margin-bottom: 14px;
}

.smart-brief-panel #autoRefreshLabel {
    color: #9ff5ef;
    font-size: 0.82rem;
    font-weight: 900;
}

.smart-brief-grid {
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 12px;
}

.smart-brief-card {
    min-height: 132px;
    display: flex;
    gap: 12px;
    padding: 14px;
    background:
        linear-gradient(145deg, rgba(255, 255, 255, 0.12), rgba(255, 255, 255, 0.055)),
        rgba(8, 18, 32, 0.72);
    border: 1px solid rgba(125, 211, 252, 0.18);
    border-radius: var(--radius);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.06);
    animation: cardPop 520ms ease both;
    transition: transform 180ms ease, border-color 180ms ease, box-shadow 180ms ease;
}

.smart-brief-card:hover {
    transform: translateY(-5px);
    border-color: rgba(94, 234, 212, 0.54);
    box-shadow: 0 24px 52px rgba(0, 0, 0, 0.28), 0 0 30px rgba(94, 234, 212, 0.12);
}

.smart-brief-card span {
    color: #9fb2c7;
    font-size: 0.72rem;
    font-weight: 900;
    text-transform: uppercase;
}

.smart-brief-card strong {
    display: block;
    margin-top: 8px;
    color: #f8fbff;
    font-size: 1.18rem;
    line-height: 1.05;
}

.smart-brief-card p {
    margin: 8px 0 0;
    color: #9fb2c7;
    font-size: 0.78rem;
    font-weight: 750;
    line-height: 1.35;
}

.smart-brief-icon {
    width: 38px;
    height: 38px;
    display: grid;
    place-items: center;
    flex: 0 0 auto;
    color: #07111f;
    background: #5eead4;
    border-radius: var(--radius);
    box-shadow: 0 14px 26px rgba(94, 234, 212, 0.2);
}

.smart-brief-card.is-alert .smart-brief-icon {
    color: #fff;
    background: var(--coral);
    box-shadow: 0 14px 26px rgba(220, 74, 54, 0.25);
}

.smart-brief-card.is-watch .smart-brief-icon {
    color: #07111f;
    background: #facc15;
    box-shadow: 0 14px 26px rgba(250, 204, 21, 0.22);
}

.hourly-card {
    border: 0;
    text-align: left;
    cursor: pointer;
}

.hourly-card.is-selected {
    background:
        linear-gradient(145deg, rgba(94, 234, 212, 0.2), rgba(14, 165, 233, 0.12)),
        rgba(255, 255, 255, 0.12);
    border-color: rgba(94, 234, 212, 0.72);
    box-shadow: 0 0 0 2px rgba(94, 234, 212, 0.18), 0 22px 44px rgba(0, 0, 0, 0.24);
}

.hourly-detail {
    margin-top: 14px;
    padding: 16px;
    display: grid;
    grid-template-columns: minmax(160px, 0.55fr) minmax(0, 1fr);
    gap: 14px;
    color: #edf7ff;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(125, 211, 252, 0.18);
    border-radius: var(--radius);
}

.hourly-detail h3 {
    margin: 0;
    color: #f8fbff;
    font-size: 1.25rem;
}

.hourly-detail-grid {
    display: grid;
    grid-template-columns: repeat(5, minmax(0, 1fr));
    gap: 10px;
}

.hourly-detail-grid span {
    min-height: 70px;
    display: grid;
    align-content: center;
    gap: 4px;
    padding: 10px;
    background: rgba(8, 18, 32, 0.52);
    border: 1px solid rgba(125, 211, 252, 0.14);
    border-radius: var(--radius);
}

.hourly-detail-grid strong {
    color: #f8fbff;
    font-size: 1rem;
}

.hourly-detail-grid small {
    color: #9fb2c7;
    font-size: 0.72rem;
    font-weight: 900;
    text-transform: uppercase;
}

.js-weather-particles {
    position: fixed;
    inset: 0;
    width: 100vw;
    height: 100vh;
    contain: strict;
    overflow: hidden;
    pointer-events: none;
}

.js-weather-particles span {
    position: absolute;
    top: -8vh;
    left: calc(2vw + (var(--x) * 0.96vw));
    width: var(--size);
    height: calc(var(--size) * 3.6);
    opacity: var(--opacity);
    background: linear-gradient(180deg, rgba(255, 255, 255, 0.88), rgba(125, 211, 252, 0.12));
    border-radius: 999px;
    transform: translateX(var(--drift)) rotate(18deg);
    animation: particleFall var(--duration) linear var(--delay) infinite;
}

.js-weather-particles.is-clear span {
    width: calc(var(--size) * 1.8);
    height: calc(var(--size) * 1.8);
    background: #facc15;
    box-shadow: 0 0 22px rgba(250, 204, 21, 0.4);
    animation-name: particleFloat;
}

.js-weather-particles.is-snow span {
    width: calc(var(--size) * 2);
    height: calc(var(--size) * 2);
    background: rgba(255, 255, 255, 0.86);
    border-radius: 50%;
    animation-name: particleFloat;
}

.js-weather-particles.is-storm span {
    background: linear-gradient(180deg, rgba(250, 204, 21, 0.95), rgba(255, 255, 255, 0.08));
    box-shadow: 0 0 18px rgba(250, 204, 21, 0.28);
}

.js-weather-particles.is-mist span,
.js-weather-particles.is-clouds span {
    height: 2px;
    width: calc(var(--size) * 10);
    background: rgba(203, 213, 225, 0.3);
    animation-name: particleDrift;
}

@keyframes particleFall {
    to {
        top: 108vh;
        transform: translateX(calc(var(--drift) * -1)) rotate(18deg);
    }
}

@keyframes particleFloat {
    0% {
        top: 102vh;
        transform: translateX(0) scale(0.9);
    }
    100% {
        top: -10vh;
        transform: translateX(var(--drift)) scale(1.18);
    }
}

@keyframes particleDrift {
    0% {
        top: calc((var(--i) % 12) * 8vh);
        transform: translateX(-12vw);
    }
    100% {
        top: calc((var(--i) % 12) * 8vh);
        transform: translateX(112vw);
    }
}

@media (max-width: 980px) {
    .smart-brief-grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }

    .hourly-detail,
    .hourly-detail-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 480px) {
    .smart-brief-panel {
        padding: 16px;
    }

    .smart-brief-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 980px) {
    .signup-login.auth-panel {
        grid-template-columns: 0.72fr 1.28fr;
    }

    .contact-section {
        grid-template-columns: 1fr;
    }

    .mail-alerts-panel {
        grid-template-columns: 1fr;
    }

    .mail-alerts-copy {
        min-height: 0;
        border-right: 0;
        border-bottom: 1px solid rgba(125, 211, 252, 0.16);
    }

    .mail-alerts-copy h2 {
        max-width: none;
    }

    .mail-alerts-meta {
        grid-template-columns: repeat(3, minmax(0, 1fr));
    }
}

@media (max-width: 760px) {
    .signup-login.auth-panel {
        width: min(100% - 22px, 520px);
        max-height: calc(100vh - 28px);
        grid-template-columns: 1fr;
        overflow-y: auto;
    }

    .auth-visual {
        min-height: 170px;
    }

    .signupForm.auth-card {
        padding: 24px;
    }

    .auth-heading h2 {
        font-size: 1.72rem;
    }

    .profile-card {
        grid-template-columns: minmax(0, 1fr);
    }

    .profile-card button {
        width: 100%;
    }

    .mail-alerts-copy,
    .mail-alerts-form {
        padding: 20px;
    }

    .mail-alerts-copy h2 {
        font-size: 2.15rem;
    }

    .mail-alerts-meta {
        grid-template-columns: 1fr;
    }

    .contact-form {
        grid-template-columns: 1fr;
    }

    .contact-form-footer {
        align-items: stretch;
        flex-direction: column;
    }

    .contact-submit {
        width: 100%;
    }
}

.command-actions {
    grid-column: 1 / -1;
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
}

.ghost-command-button {
    min-height: 44px;
    display: inline-flex;
    align-items: center;
    gap: 9px;
    padding: 0 14px;
    color: #ddfffb;
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(125, 211, 252, 0.22);
    border-radius: var(--radius);
    box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.08);
    cursor: pointer;
    font-size: 0.86rem;
    font-weight: 900;
    transition: transform 180ms ease, border-color 180ms ease, background-color 180ms ease, box-shadow 180ms ease;
}

.ghost-command-button:hover {
    transform: translateY(-3px);
    border-color: rgba(94, 234, 212, 0.62);
    background: rgba(94, 234, 212, 0.12);
    box-shadow: 0 16px 34px rgba(0, 0, 0, 0.22);
}

.favorite-places-panel,
.mission-control,
.decision-board {
    margin-top: 16px;
    scroll-margin-top: 148px;
    border-radius: var(--radius);
    animation: riseIn 580ms ease both;
}

.favorite-places-panel,
.decision-board {
    padding: 20px;
    background:
        linear-gradient(135deg, rgba(255, 255, 255, 0.95), rgba(239, 246, 255, 0.9)),
        var(--surface);
    border: 1px solid rgba(216, 224, 232, 0.88);
    box-shadow: var(--shadow);
}

.favorite-places-panel .section-heading,
.decision-board .section-heading {
    margin-bottom: 14px;
}

#favoritePlacesCount,
.decision-board .section-heading > span {
    color: var(--muted);
    font-size: 0.82rem;
    font-weight: 900;
}

.favorite-places-panel .section-heading h2,
.decision-board .section-heading h2 {
    color: var(--ink);
}

.favorite-places-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: 10px;
}

.favorite-place-card {
    min-width: 0;
    display: grid;
    grid-template-columns: minmax(0, 1fr) 40px;
    gap: 8px;
    align-items: stretch;
    padding: 8px;
    background: rgba(255, 255, 255, 0.72);
    border: 1px solid rgba(216, 224, 232, 0.92);
    border-radius: var(--radius);
    transition: transform 180ms ease, border-color 180ms ease, box-shadow 180ms ease;
}

.favorite-place-card:hover,
.favorite-place-card.is-active {
    transform: translateY(-3px);
    border-color: rgba(15, 118, 110, 0.36);
    box-shadow: 0 14px 30px rgba(23, 33, 47, 0.1);
}

.favorite-place-card.is-active {
    background: linear-gradient(135deg, rgba(204, 251, 241, 0.82), rgba(239, 246, 255, 0.9));
}

.favorite-place-load,
.favorite-place-remove {
    border-radius: 6px;
    cursor: pointer;
}

.favorite-place-load {
    min-width: 0;
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 10px;
    color: var(--ink);
    background: transparent;
    text-align: left;
}

.favorite-place-load svg {
    flex: 0 0 auto;
    color: var(--teal);
}

.favorite-place-load span {
    min-width: 0;
    display: grid;
    gap: 3px;
}

.favorite-place-load strong,
.favorite-place-load small {
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.favorite-place-load strong {
    font-size: 0.92rem;
}

.favorite-place-load small {
    color: var(--muted);
    font-size: 0.76rem;
    font-weight: 800;
}

.favorite-place-remove {
    display: grid;
    place-items: center;
    color: var(--muted);
    background: rgba(23, 33, 47, 0.06);
}

.favorite-place-remove:hover {
    color: #fff;
    background: var(--coral);
}

.mission-control {
    position: relative;
    display: grid;
    grid-template-columns: minmax(260px, 0.85fr) minmax(170px, 0.36fr) minmax(360px, 1.15fr);
    gap: 16px;
    padding: 22px;
    overflow: hidden;
    color: #edf7ff;
    background:
        radial-gradient(circle at 18% 20%, rgba(94, 234, 212, 0.2), transparent 32%),
        radial-gradient(circle at 84% 18%, rgba(250, 204, 21, 0.15), transparent 28%),
        linear-gradient(135deg, rgba(8, 18, 32, 0.96), rgba(15, 35, 54, 0.9)),
        #081220;
    border: 1px solid rgba(125, 211, 252, 0.22);
    box-shadow: 0 28px 70px rgba(0, 0, 0, 0.32);
}

.mission-control::before {
    content: "";
    position: absolute;
    inset: 0;
    pointer-events: none;
    background:
        linear-gradient(90deg, rgba(125, 211, 252, 0.07) 1px, transparent 1px),
        linear-gradient(rgba(125, 211, 252, 0.06) 1px, transparent 1px);
    background-size: 44px 44px;
    opacity: 0.45;
}

.mission-control > * {
    position: relative;
    z-index: 1;
}

.mission-copy {
    display: grid;
    align-content: center;
}

.mission-copy h2 {
    margin: 0 0 10px;
    color: #fff;
    font-size: clamp(2rem, 3.4vw, 3.25rem);
    line-height: 0.98;
}

.mission-copy p:not(.eyebrow) {
    margin: 0;
    color: rgba(237, 247, 255, 0.72);
    font-weight: 780;
    line-height: 1.52;
}

.mission-score-card {
    min-height: 180px;
    display: grid;
    place-items: center;
    align-content: center;
    gap: 8px;
    color: #07111f;
    background: conic-gradient(from 180deg, #5eead4, #facc15, #38bdf8, #5eead4);
    border: 1px solid rgba(255, 255, 255, 0.34);
    border-radius: var(--radius);
    box-shadow: 0 20px 48px rgba(94, 234, 212, 0.18);
}

.mission-score-card span {
    font-size: clamp(3rem, 6vw, 4.8rem);
    font-weight: 900;
    line-height: 0.9;
}

.mission-score-card small {
    max-width: 120px;
    text-align: center;
    font-size: 0.78rem;
    font-weight: 950;
    text-transform: uppercase;
}

.mission-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 10px;
}

.mission-card,
.planner-card,
.risk-meter {
    min-width: 0;
    border-radius: var(--radius);
}

.mission-card {
    min-height: 146px;
    display: grid;
    align-content: start;
    gap: 7px;
    padding: 14px;
    background: rgba(255, 255, 255, 0.09);
    border: 1px solid rgba(125, 211, 252, 0.16);
}

.mission-card svg,
.planner-icon {
    width: 38px;
    height: 38px;
    display: grid;
    place-items: center;
    padding: 9px;
    color: #07111f;
    background: #5eead4;
    border-radius: var(--radius);
}

.mission-card.is-watch svg,
.planner-card.is-watch .planner-icon {
    background: #facc15;
}

.mission-card.is-alert svg,
.planner-card.is-alert .planner-icon {
    color: #fff;
    background: var(--coral);
}

.mission-card span,
.planner-card span,
.risk-meter span {
    display: block;
    color: #9fb2c7;
    font-size: 0.72rem;
    font-weight: 900;
    text-transform: uppercase;
}

.mission-card strong,
.planner-card strong {
    display: block;
    margin-top: 4px;
    color: #fff;
    font-size: 1.08rem;
    line-height: 1.1;
}

.mission-card p,
.planner-card p {
    margin: 0;
    color: #a9bdd2;
    font-size: 0.78rem;
    font-weight: 750;
    line-height: 1.35;
}

.planner-grid {
    display: grid;
    grid-template-columns: repeat(4, minmax(0, 1fr));
    gap: 12px;
}

.planner-card {
    min-height: 158px;
    display: grid;
    align-content: start;
    gap: 12px;
    padding: 16px;
    background: linear-gradient(145deg, rgba(8, 18, 32, 0.94), rgba(15, 35, 54, 0.88));
    border: 1px solid rgba(125, 211, 252, 0.16);
    box-shadow: 0 14px 32px rgba(23, 33, 47, 0.12);
}

.risk-radar-grid {
    display: grid;
    grid-template-columns: repeat(5, minmax(0, 1fr));
    gap: 10px;
    margin-top: 14px;
}

.risk-meter {
    min-height: 116px;
    display: grid;
    gap: 10px;
    padding: 13px;
    background: rgba(255, 255, 255, 0.72);
    border: 1px solid rgba(216, 224, 232, 0.9);
}

.risk-meter > div:first-child {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 10px;
}

.risk-meter strong {
    color: var(--ink);
    font-size: 1.15rem;
}

.risk-track {
    height: 9px;
    overflow: hidden;
    background: rgba(23, 33, 47, 0.09);
    border-radius: 999px;
}

.risk-track span {
    width: calc(var(--risk) * 1%);
    height: 100%;
    display: block;
    background: linear-gradient(90deg, #22c55e, #facc15 55%, #dc4a36);
    border-radius: inherit;
}

.risk-meter p {
    margin: 0;
    color: var(--muted);
    font-size: 0.76rem;
    font-weight: 780;
    line-height: 1.35;
}

.readiness-checklist {
    display: flex;
    flex-wrap: wrap;
    gap: 8px;
    margin-top: 14px;
}

.readiness-chip {
    min-height: 38px;
    display: inline-flex;
    align-items: center;
    gap: 8px;
    padding: 0 12px;
    color: var(--teal-dark);
    background: rgba(15, 118, 110, 0.1);
    border: 1px solid rgba(15, 118, 110, 0.16);
    border-radius: var(--radius);
    font-size: 0.82rem;
    font-weight: 900;
}

.readiness-chip.is-watch {
    color: #854d0e;
    background: rgba(250, 204, 21, 0.16);
    border-color: rgba(217, 119, 6, 0.22);
}

.readiness-chip.is-alert {
    color: #9f1d1d;
    background: rgba(220, 74, 54, 0.12);
    border-color: rgba(220, 74, 54, 0.22);
}

@media (max-width: 1080px) {
    .mission-control {
        grid-template-columns: 1fr 180px;
    }

    .mission-grid {
        grid-column: 1 / -1;
    }

    .planner-grid,
    .risk-radar-grid,
    .favorite-places-grid {
        grid-template-columns: repeat(2, minmax(0, 1fr));
    }
}

@media (max-width: 760px) {
    .command-actions {
        display: grid;
        grid-template-columns: 1fr;
    }

    .mission-control,
    .mission-grid,
    .planner-grid,
    .risk-radar-grid,
    .favorite-places-grid {
        grid-template-columns: 1fr;
    }

    .mission-score-card {
        min-height: 150px;
    }
}

/* High-refresh canvas background: one paint surface, no layout-heavy particle DOM. */
.weather-effects {
    background:
        radial-gradient(circle at 20% 18%, rgba(14, 165, 233, 0.28), transparent 32%),
        radial-gradient(circle at 72% 10%, rgba(250, 204, 21, 0.16), transparent 26%),
        radial-gradient(circle at 82% 78%, rgba(20, 184, 166, 0.18), transparent 30%),
        linear-gradient(145deg, rgba(7, 17, 31, 0.96), rgba(10, 32, 48, 0.92));
    contain: strict;
    max-width: 100vw;
    overflow: clip;
}

.weather-canvas {
    position: fixed;
    inset: 0;
    width: 100vw !important;
    height: 100vh !important;
    display: block;
    transform: translateZ(0);
    contain: strict;
}

.weather-effects::before {
    inset: 0;
    opacity: 0.32;
    transform: none;
    animation: none;
    background:
        linear-gradient(90deg, rgba(125, 211, 252, 0.08) 1px, transparent 1px),
        linear-gradient(rgba(125, 211, 252, 0.07) 1px, transparent 1px);
    background-size: 78px 78px;
}

.weather-effects::after {
    opacity: 0.36;
    animation: none;
}

.sky-ribbon,
.storm-flash,
.rain-field,
.wind-streams,
.float-icon,
.js-weather-particles {
    display: none !important;
}

.topbar,
.search-form,
.signal-card,
.smart-brief-card,
.insight-card,
.metric-card,
.forecast-card,
.air-chip {
    backdrop-filter: none !important;
}

.radar-sweep,
.radar-core,
.weather-orbit,
.hourly-card,
.smart-brief-card,
.insight-card,
.metric-card {
    will-change: transform;
}

.dashboard > section,
.weather-dashboard > section,
.contact-form {
    contain: layout paint;
}

@media (prefers-reduced-motion: reduce) {
    *,
    *::before,
    *::after {
        animation-duration: 1ms !important;
        animation-iteration-count: 1 !important;
        scroll-behavior: auto !important;
        transition-duration: 1ms !important;
    }
}
